    const n = nums.length;
    const ans: number[] = [];

    // Preprocess the array to create a frequency map for every possible subarray
    // However, due to time constraints, we will process each query directly

    for (const [li, ri, threshold] of queries) {
        const freq: Map<number, number> = new Map();
